arguments.file_text:
namespace sv_cd4ca7619e3043aeb159ff423dde03fd.Models;

public class ApplicationState
{
    // Step 1: Personal Info
    public string FullName { get; set; } = string.Empty;
    public string Email { get; set; } = string.Empty;

    // Step 2: Experience
    public List<JobEntry> JobHistory { get; set; } = [];

    // Step 3: References
    public List<ReferenceContact> References { get; set; } = [];

    public bool HasPersonalInfo => !string.IsNullOrWhiteSpace(FullName) && !string.IsNullOrWhiteSpace(Email);
    public bool HasExperience => JobHistory.Count > 0;
    public bool HasReferences => References.Count > 0;
}

public class JobEntry
{
    public string Company { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public string Years { get; set; } = string.Empty;
}

public class ReferenceContact
{
    public string Name { get; set; } = string.Empty;
    public string Relationship { get; set; } = string.Empty;
    public string Phone { get; set; } = string.Empty;
}

using System.Collections.Concurrent;
using sv_cd4ca7619e3043aeb159ff423dde03fd.Models;

namespace sv_cd4ca7619e3043aeb159ff423dde03fd.Services;

/// <summary>
/// Singleton service that stores wizard state keyed by session ID.
/// Both static-SSR layout and interactive pages resolve the session ID
/// from HttpContext.Session during the initial HTTP request, then use
/// this service to read/write shared wizard data.
/// </summary>
public class ApplicationWizardService
{
    private readonly ConcurrentDictionary<string, ApplicationState> _store = new();

    public ApplicationState GetOrCreate(string sessionId)
        => _store.GetOrAdd(sessionId, _ => new ApplicationState());

    public void Save(string sessionId, ApplicationState state)
        => _store[sessionId] = state;
}

