@using sv_cd4ca7619e3043aeb159ff423dde03fd.Services
@inject ApplicationWizardService WizardService
@inject IHttpContextAccessor HttpContextAccessor

@{
    var path = HttpContextAccessor.HttpContext?.Request.Path.Value ?? "";
    var isWizard = path.StartsWith("/apply/", StringComparison.OrdinalIgnoreCase);
}

@if (isWizard)
{
    var sessionId = HttpContextAccessor.HttpContext!.Session.Id;
    var state = WizardService.GetOrCreate(sessionId);

    var steps = new (string Href, string Label, bool Completed)[]
    {
        ("/apply/personal-info", "Personal Info", state.HasPersonalInfo),
        ("/apply/experience",    "Experience",    state.HasExperience),
        ("/apply/references",    "References",    state.HasReferences),
        ("/apply/review",        "Review",        false),
    };

    int currentIndex = Array.FindIndex(steps, s => path.Equals(s.Href, StringComparison.OrdinalIgnoreCase));
    if (currentIndex < 0) currentIndex = 0;

    <nav class="wizard-progress mb-4">
        <div class="d-flex justify-content-between align-items-center mb-2">
            <strong>Step @(currentIndex + 1) of @steps.Length</strong>
        </div>
        <div class="progress mb-3" style="height: 8px;">
            <div class="progress-bar" role="progressbar"
                 style="width: @((currentIndex + 1) * 100 / steps.Length)%">
            </div>
        </div>
        <ul class="nav nav-pills">
            @for (int i = 0; i < steps.Length; i++)
            {
                var step = steps[i];
                var css = i == currentIndex ? "nav-link active"
                        : step.Completed   ? "nav-link text-success"
                                           : "nav-link";
                <li class="nav-item">
                    <a href="@step.Href" class="@css">
                        @if (step.Completed && i != currentIndex)
                        {
                            <span>&#10003; </span>
                        }
                        @step.Label
                    </a>
                </li>
            }
        </ul>
    </nav>
}

