@page "/apply/personal-info"
@rendermode InteractiveServer

@using sv_cd4ca7619e3043aeb159ff423dde03fd.Models
@using sv_cd4ca7619e3043aeb159ff423dde03fd.Services

@inject ApplicationWizardService WizardService
@inject IHttpContextAccessor HttpContextAccessor
@inject NavigationManager Nav

<PageTitle>Personal Info</PageTitle>
<h1>Personal Information</h1>

<EditForm Model="model" OnValidSubmit="Next" FormName="personal-info">
    <div class="mb-3">
        <label class="form-label">Full Name</label>
        <InputText class="form-control" @bind-Value="model.FullName" />
    </div>
    <div class="mb-3">
        <label class="form-label">Email</label>
        <InputText class="form-control" @bind-Value="model.Email" />
    </div>
    <button type="submit" class="btn btn-primary">Next &rarr;</button>
</EditForm>

@code {
    private PersonalInfoModel model = new();
    private string sessionId = default!;

    protected override void OnInitialized()
    {
        sessionId = HttpContextAccessor.HttpContext!.Session.Id;
        var state = WizardService.GetOrCreate(sessionId);
        model.FullName = state.FullName;
        model.Email = state.Email;
    }

    private void Next()
    {
        var state = WizardService.GetOrCreate(sessionId);
        state.FullName = model.FullName;
        state.Email = model.Email;
        Nav.NavigateTo("/apply/experience");
    }

    private sealed class PersonalInfoModel
    {
        public string FullName { get; set; } = string.Empty;
        public string Email { get; set; } = string.Empty;
    }
}

@page "/apply/experience"
@rendermode InteractiveServer

@using sv_cd4ca7619e3043aeb159ff423dde03fd.Models
@using sv_cd4ca7619e3043aeb159ff423dde03fd.Services

@inject ApplicationWizardService WizardService
@inject IHttpContextAccessor HttpContextAccessor
@inject NavigationManager Nav

<PageTitle>Experience</PageTitle>
<h1>Job Experience</h1>

@if (jobs.Count > 0)
{
    <table class="table table-sm mb-3">
        <thead>
            <tr><th>Company</th><th>Title</th><th>Years</th><th></th></tr>
        </thead>
        <tbody>
            @foreach (var job in jobs)
            {
                <tr>
                    <td>@job.Company</td>
                    <td>@job.Title</td>
                    <td>@job.Years</td>
                    <td><button class="btn btn-sm btn-outline-danger" @onclick="() => jobs.Remove(job)">Remove</button></td>
                </tr>
            }
        </tbody>
    </table>
}

<div class="card p-3 mb-3">
    <h5>Add Job Entry</h5>
    <div class="row g-2">
        <div class="col-md-4">
            <input class="form-control" placeholder="Company" @bind="newJob.Company" />
        </div>
        <div class="col-md-4">
            <input class="form-control" placeholder="Title" @bind="newJob.Title" />
        </div>
        <div class="col-md-2">
            <input class="form-control" placeholder="Years" @bind="newJob.Years" />
        </div>
        <div class="col-md-2">
            <button class="btn btn-secondary w-100" @onclick="AddJob">Add</button>
        </div>
    </div>
</div>

<div class="d-flex gap-2">
    <a href="/apply/personal-info" class="btn btn-outline-secondary">&larr; Back</a>
    <button class="btn btn-primary" @onclick="Next">Next &rarr;</button>
</div>

@code {
    private List<JobEntry> jobs = [];
    private JobEntry newJob = new();
    private string sessionId = default!;

    protected override void OnInitialized()
    {
        sessionId = HttpContextAccessor.HttpContext!.Session.Id;
        var state = WizardService.GetOrCreate(sessionId);
        jobs = state.JobHistory.Select(j => new JobEntry
        {
            Company = j.Company, Title = j.Title, Years = j.Years
        }).ToList();
    }

    private void AddJob()
    {
        if (!string.IsNullOrWhiteSpace(newJob.Company))
        {
            jobs.Add(newJob);
            newJob = new();
        }
    }

    private void Next()
    {
        SaveState();
        Nav.NavigateTo("/apply/references");
    }

    private void SaveState()
    {
        var state = WizardService.GetOrCreate(sessionId);
        state.JobHistory = jobs.Select(j => new JobEntry
        {
            Company = j.Company, Title = j.Title, Years = j.Years
        }).ToList();
    }
}

@page "/apply/references"
@rendermode InteractiveServer

