                    <td><button class="btn btn-sm btn-outline-danger" @onclick="() => refs.Remove(r)">Remove</button></td>
                </tr>
            }
        </tbody>
    </table>
}

<div class="card p-3 mb-3">
    <h5>Add Reference</h5>
    <div class="row g-2">
        <div class="col-md-4">
            <input class="form-control" placeholder="Name" @bind="newRef.Name" />
        </div>
        <div class="col-md-4">
            <input class="form-control" placeholder="Relationship" @bind="newRef.Relationship" />
        </div>
        <div class="col-md-3">
            <input class="form-control" placeholder="Phone" @bind="newRef.Phone" />
        </div>
        <div class="col-md-1">
            <button class="btn btn-secondary w-100" @onclick="AddRef">Add</button>
        </div>
    </div>
</div>

<div class="d-flex gap-2">
    <a href="/apply/experience" class="btn btn-outline-secondary">&larr; Back</a>
    <button class="btn btn-primary" @onclick="Next">Next &rarr;</button>
</div>

@code {
    private List<ReferenceContact> refs = [];
    private ReferenceContact newRef = new();
    private string sessionId = default!;

    protected override void OnInitialized()
    {
        sessionId = HttpContextAccessor.HttpContext!.Session.Id;
        var state = WizardService.GetOrCreate(sessionId);
        refs = state.References.Select(r => new ReferenceContact
        {
            Name = r.Name, Relationship = r.Relationship, Phone = r.Phone
        }).ToList();
    }

    private void AddRef()
    {
        if (!string.IsNullOrWhiteSpace(newRef.Name))
        {
            refs.Add(newRef);
            newRef = new();
        }
    }

    private void Next()
    {
        SaveState();
        Nav.NavigateTo("/apply/review");
    }

    private void SaveState()
    {
        var state = WizardService.GetOrCreate(sessionId);
        state.References = refs.Select(r => new ReferenceContact
        {
            Name = r.Name, Relationship = r.Relationship, Phone = r.Phone
        }).ToList();
    }
}

