@page "/apply/experience"
@rendermode InteractiveServer

@using sv_cd4ca7619e3043aeb159ff423dde03fd.Models
@using sv_cd4ca7619e3043aeb159ff423dde03fd.Services

@inject ApplicationWizardService WizardService
@inject IHttpContextAccessor HttpContextAccessor
@inject NavigationManager Nav

<PageTitle>Experience</PageTitle>
<h1>Job Experience</h1>

@if (jobs.Count > 0)
{
    <table class="table table-sm mb-3">
        <thead>
            <tr><th>Company</th><th>Title</th><th>Years</th><th></th></tr>
        </thead>
        <tbody>
            @foreach (var job in jobs)
            {
                <tr>
                    <td>@job.Company</td>
                    <td>@job.Title</td>
                    <td>@job.Years</td>
                    <td><button class="btn btn-sm btn-outline-danger" @onclick="() => jobs.Remove(job)">Remove</button></td>
                </tr>
            }
        </tbody>
    </table>
}

<div class="card p-3 mb-3">
    <h5>Add Job Entry</h5>
    <div class="row g-2">
        <div class="col-md-4">
            <input class="form-control" placeholder="Company" @bind="newJob.Company" />
        </div>
        <div class="col-md-4">
            <input class="form-control" placeholder="Title" @bind="newJob.Title" />
        </div>
        <div class="col-md-2">
            <input class="form-control" placeholder="Years" @bind="newJob.Years" />
        </div>
        <div class="col-md-2">
            <button class="btn btn-secondary w-100" @onclick="AddJob">Add</button>
        </div>
    </div>
</div>

<div class="d-flex gap-2">
    <a href="/apply/personal-info" class="btn btn-outline-secondary">&larr; Back</a>
    <button class="btn btn-primary" @onclick="Next">Next &rarr;</button>
</div>

@code {
    private List<JobEntry> jobs = [];
    private JobEntry newJob = new();
    private string sessionId = default!;

    protected override void OnInitialized()
    {
        sessionId = HttpContextAccessor.HttpContext!.Session.Id;
        var state = WizardService.GetOrCreate(sessionId);
        jobs = state.JobHistory.Select(j => new JobEntry
        {
            Company = j.Company, Title = j.Title, Years = j.Years
        }).ToList();
    }

    private void AddJob()
    {
        if (!string.IsNullOrWhiteSpace(newJob.Company))
        {
            jobs.Add(newJob);
            newJob = new();
        }
    }

    private void Next()
    {
        SaveState();
        Nav.NavigateTo("/apply/references");
    }

    private void SaveState()
    {
        var state = WizardService.GetOrCreate(sessionId);
        state.JobHistory = jobs.Select(j => new JobEntry
        {
            Company = j.Company, Title = j.Title, Years = j.Years
        }).ToList();
    }
}

@page "/apply/review"
@rendermode InteractiveServer

@using sv_cd4ca7619e3043aeb159ff423dde03fd.Models
@using sv_cd4ca7619e3043aeb159ff423dde03fd.Services

@inject ApplicationWizardService WizardService
@inject IHttpContextAccessor HttpContextAccessor

<PageTitle>Review Application</PageTitle>
<h1>Review Your Application</h1>

@if (state is not null)
{
    <div class="card mb-3">
        <div class="card-header"><strong>Personal Information</strong></div>
        <div class="card-body">
            <p><strong>Name:</strong> @state.FullName</p>
            <p><strong>Email:</strong> @state.Email</p>
        </div>
    </div>

    <div class="card mb-3">
        <div class="card-header"><strong>Experience</strong></div>
        <div class="card-body">
            @if (state.JobHistory.Count == 0)
            {
                <p class="text-muted">No job history entered.</p>
            }
            else
            {
                <table class="table table-sm mb-0">
                    <thead><tr><th>Company</th><th>Title</th><th>Years</th></tr></thead>
                    <tbody>
                        @foreach (var job in state.JobHistory)
                        {
                            <tr><td>@job.Company</td><td>@job.Title</td><td>@job.Years</td></tr>
                        }
                    </tbody>
                </table>
            }
        </div>
    </div>

    <div class="card mb-3">
        <div class="card-header"><strong>References</strong></div>
        <div class="card-body">
            @if (state.References.Count == 0)
            {
                <p class="text-muted">No references entered.</p>
            }
            else
            {
                <table class="table table-sm mb-0">
                    <thead><tr><th>Name</th><th>Relationship</th><th>Phone</th></tr></thead>
                    <tbody>
                        @foreach (var r in state.References)
                        {
                            <tr><td>@r.Name</td><td>@r.Relationship</td><td>@r.Phone</td></tr>
                        }
                    </tbody>
                </table>
            }
        </div>
    </div>

    <div class="d-flex gap-2">
        <a href="/apply/references" class="btn btn-outline-secondary">&larr; Back</a>
        <button class="btn btn-success" @onclick="Submit">Submit Application</button>
    </div>

    @if (submitted)
    {
        <div class="alert alert-success mt-3">Your application has been submitted!</div>
    }
}

@code {
    private ApplicationState? state;
    private bool submitted;

    protected override void OnInitialized()
    {
        var sessionId = HttpContextAccessor.HttpContext!.Session.Id;
        state = WizardService.GetOrCreate(sessionId);
    }

    private void Submit()
    {
        submitted = true;
    }
}
